ee:variables.ee:set-variable:
%dw 2.0
output application/java
var p = if (payload is String) read(payload, "application/json") else payload
var fromAttr = (attributes.contextId default "") as String
var fromMsg  = (p.message.contextId default "") as String
---
// クライアントが contextId を送ってきたらそれを使う。 無ければ taskId をベースに採番して
// 応答 (taskJson) で返す。 クライアント (a2a.js) は応答の contextId を保持し次ターンから送るので、
// 同一 window 内では会話が継続する (「さっきのインシデントをクローズ」が効く)。
if (fromAttr != "") fromAttr
else if (fromMsg != "") fromMsg
else ("ctx-" ++ ((attributes.taskId default (now() as String)) as String))

%dw 2.0
output application/java
var p = if (payload is String) read(payload, "application/json") else payload
var parts = (p.message.parts default [])
var textPart = (parts filter ((x) -> (x.kind default x."type" default "") == "text"))
---
if (sizeOf(textPart) > 0) ((textPart[0].text default "") as String)
else (((parts[0].text default "") as String))

%dw 2.0
output application/java
var t = ((vars.finalText default "") as String)
var msgs = (vars.messages default [])
var lastAssistant = (msgs filter ((m) -> ((m.role default "") as String) == "assistant" and ((m.content default "") as String) != ""))
var lastAssistantContent = if (sizeOf(lastAssistant) > 0) ((lastAssistant[-1].content default "") as String) else ""
var fallbackByReason =
  if ((vars.finishReason default "") as String == "length")
    "ℹ️ インシデント管理 (atelier-incident-agent) です。\n\n回答が文字数上限に達しました。\nincidentId か (サプライヤー名 + 部品番号 + 不具合内容) を指定して再度お試しください。"
  else
    "ℹ️ インシデント管理 (atelier-incident-agent) です。\n\n**実行可能な操作**\n- 取引先のゴールデン ID 解決\n- 過去インシデント・取引先関係の照会\n- 取引先一覧 (region / status / リスクスコア範囲で絞込み)\n- 取引先 region 一覧 (各 region の件数付き)\n- 既存 incidentId の状態照会\n- インシデントの新規採番 (Incident__c 作成)\n- インシデントステータスの更新 (OPEN / IN_PROGRESS / RESOLVED)\n\nincidentId か (サプライヤー名 + 部品番号 + 不具合内容) を教えてください。"
---
if (t != "") t
else if (lastAssistantContent != "") lastAssistantContent
else fallbackByReason

%dw 2.0
output application/json
---
{
  id: vars.taskId,
  contextId: vars.contextId,
  kind: "task",
  status: {
    state: "completed",
    message: {
      role: "agent",
      kind: "message",
      messageId: (now() as String) ++ "-" ++ vars.taskId,
      parts: [
        { kind: "text", text: vars.replyText default "" }
      ]
    },
    timestamp: now() as String { format: "yyyy-MM-dd'T'HH:mm:ss'Z'" }
  }
}

%dw 2.0
output application/java
---
[
  { "type": "function", "function": {
      name: "lookup_incident",
      description: "incidentId で既存 Incident__c を 1 件取得する。404 のときは exists=false を返す",
      parameters: {
        "type": "object",
        properties: {
          incidentId: { "type": "string" }
        },
        required: ["incidentId"]
      }
  }},
  { "type": "function", "function": {
      name: "register_incident",
      description: "Incident__c を新規作成する。incidentId 未指定なら incident-system が採番。supplierGoldenId / partNumber / severity / rawMessage は必須",
      parameters: {
        "type": "object",
        properties: {
          incidentId:       { "type": "string" },
          supplierGoldenId: { "type": "string" },
          partNumber:       { "type": "string" },
          quantity:         { "type": "integer" },
          severity:         { "type": "string", "enum": ["LOW", "MEDIUM", "HIGH", "CRITICAL"] },
          rawMessage:       { "type": "string" },
          slackChannel:     { "type": "string" },
          slackThreadTs:    { "type": "string" }
        },
        required: ["supplierGoldenId", "partNumber", "severity", "rawMessage"]
      }
  }},
  { "type": "function", "function": {
      name: "update_incident_status",
      description: "incidentId のステータスを更新する。OPEN / IN_PROGRESS / RESOLVED",
      parameters: {
        "type": "object",
        properties: {
          incidentId: { "type": "string" },
          status:     { "type": "string", "enum": ["OPEN", "IN_PROGRESS", "RESOLVED"] }
        },
        required: ["incidentId", "status"]
      }
  }},
  { "type": "function", "function": {
      name: "list_incidents",
      description: "インシデント一覧を取得する READ-ONLY ツール。CreatedDate DESC、既定 limit=10 (上限 50)。全パラメータ任意 — 何も指定しなければ最新一覧を返す。supplierGoldenId / partNumber / status (OPEN/IN_PROGRESS/RESOLVED/ALL) / severity / since (ISO日付) / limit で絞り込める。一覧・照会の依頼にはこのツールを使う (register は不要)。",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          partNumber:       { "type": "string" },
          status:           { "type": "string" },
          severity:         { "type": "string" },
          since:            { "type": "string" },
          limit:            { "type": "integer" }
        },
        required: []
      }
  }}
]

%dw 2.0
output application/java
// LLM 出力からコードフェンスや前後の散文を除去し、 最初の { 〜 最後の } を JSON として読む
fun extractJson(s) = do {
  var t = trim(s default "")
  var noFence = (t replace /```(json)?/ with "") replace "```" with ""
  var i = noFence indexOf "{"
  var j = noFence lastIndexOf "}"
  ---
  if (i >= 0 and j > i) (noFence[i to j]) else "{}"
}
// 不正/途中切れ JSON でも落ちないよう try で包む (read は default では捕まらず throw)。
fun safeReadJson(s) =
  if (s == null or (trim(s as String)) == "") {}
  else (dw::Runtime::try(() -> read(extractJson(s as String), "application/json")).result default {})
// HTTP レスポンス payload は Binary のことがあるので明示的に JSON 化してから choices を読む
var resp =
  if (payload == null) {}
  else if (payload is Binary) (dw::Runtime::try(() -> read(payload as String {encoding: "UTF-8"}, "application/json")).result default {})
  else if (payload is String) (dw::Runtime::try(() -> read(payload as String, "application/json")).result default {})
  else payload
var raw = ((resp.choices default [])[0].message.content default "{}") as String
var obj = safeReadJson(raw)
// ── 決定論バックフィル: userText から正規表現で確実に拾える値を、 LLM が null に
//    した場合だけ補う。 gpt-5-mini の抽出ブレ (partNumber/incidentId 取りこぼし) を
//    打ち消し、 デモを安定させる。 LLM が入れた値は尊重し上書きしない。 ──
var ut = (vars.userText default "") as String
fun firstMatch(re) = do { var m = (ut scan re) --- if (sizeOf(m) > 0) m[0][0] else null }
var rxPart  = firstMatch(/P-\d{4}-[A-Z0-9]+-\d+/)
var rxInc   = firstMatch(/INC-[0-9A-Za-z-]+/)
var rxSev   = upper(((firstMatch(/(?i)(CRITICAL|HIGH|MEDIUM|LOW)/)) default "") as String)
var rxQty   = do { var m = (ut scan /(\d+)\s*(台|個|pcs|units?)/) --- if (sizeOf(m) > 0) (m[0][1]) else null }
var llmEnts = (obj.entities default {})
var ents = llmEnts ++
  (if ((llmEnts.partNumber  default null) == null and rxPart != null) { partNumber: rxPart } else {}) ++
  (if ((llmEnts.incidentId  default null) == null and rxInc  != null) { incidentId: rxInc } else {}) ++
  (if ((llmEnts.severity    default null) == null and rxSev != "")    { severity: rxSev } else {}) ++
  (if ((llmEnts.quantity    default null) == null and rxQty != null)  { quantity: (rxQty as Number) } else {})
---
{
  intent:     (obj.intent default "unknown") as String,
  entities:   ents,
  rawMessage: (obj.rawMessage default ((vars.userText default "") as String)) as String,
  language:   (obj.language default "ja") as String
}

%dw 2.0
output application/java
var r  = (vars.toolResult.result default vars.toolResult default {})
var gid = if ((r.matched default false) == true) (r.supplier.goldenId default null) else null
---
vars.intent ++ {
  entities: (vars.intent.entities default {}) ++
    (if (gid != null) { supplierGoldenId: gid } else {})
}

%dw 2.0
output application/java
var e = vars.intent.entities default {}
---
{ incidentId: e.incidentId, status: e.status }

%dw 2.0
output application/java
var e  = vars.intent.entities default {}
var tr = vars.toolResult default {}
// MCP/backend がエラー (存在しない incidentId 等) を返したら成功を偽らない。
var isErr = ((tr.status default "") as String) == "error"
var code  = (tr.result.code default "") as String
var msg   = (tr.result.message default "") as String
---
if (isErr)
  "⚠️ ステータスを更新できませんでした。 **" ++ (e.incidentId default "?" as String) ++ "**"
    ++ (if (code == "NOT_FOUND") " — 該当インシデントが見つかりません。 incidentId をご確認ください。"
        else " — " ++ (if (msg != "") msg else code))
else
  "✅ ステータスを更新しました。 **" ++ (e.incidentId as String) ++ "** → **" ++ (e.status as String) ++ "**"

%dw 2.0
output application/java
var r = (vars.toolResult.result default vars.toolResult default {})
var items = (r.items default [])
---
// 既に RESOLVED のものは除く。 incidentId が取れるものだけ。
(items
  filter ((it) -> ((it.status default "") as String) != "RESOLVED")
  map ((it) -> (it.incidentId default it.name default "") as String)
  filter ((id) -> id != "")) distinctBy ((id) -> id)

%dw 2.0
output application/java
var res = (vars.bulkResults default [])
var okList = res filter ((x) -> x.ok == true)
var ngList = res filter ((x) -> x.ok != true)
---
"✅ 一括クローズ完了: **" ++ (sizeOf(okList) as String) ++ " 件**を RESOLVED にしました。\n\n" ++
(okList map ((x) -> "- **" ++ (x.incidentId as String) ++ "** → RESOLVED") joinBy "\n") ++
(if (sizeOf(ngList) > 0)
  ("\n\n⚠️ 失敗 " ++ (sizeOf(ngList) as String) ++ " 件:\n" ++
   (ngList map ((x) -> "- " ++ (x.incidentId as String)) joinBy "\n"))
 else "")

%dw 2.0
output application/java
fun safeReadJson(s: String) =
  if (s == null or trim(s) == "") {}
  else read(s, "application/json")
---
if (payload == null) {}
else if (payload is Binary) safeReadJson(payload as String { encoding: "UTF-8" })
else if (payload is String) safeReadJson(payload as String)
else payload

ee:message.ee:set-payload:
%dw 2.0
output application/java
// 新パイプライン (intent抽出) 用の会話メモリ。 旧 vars.messages ではなく、
// loadMemoryFlow が読んだ priorMessages に「今回の user 発話 + agent 応答」を足して
// 直近ターンだけ残す。 これで次ターンが「さっきの INC」を参照できる。
var prior = (vars.priorMessages default []) filter ((m) ->
  (((m.role default "") as String) == "user" or ((m.role default "") as String) == "assistant")
  and ((m.content default "") as String) != "")
var thisTurn = [
  { role: "user",      content: (vars.userText default "") as String },
  { role: "assistant", content: (vars.replyText default vars.finalText default "") as String }
]
var all = prior ++ thisTurn
// 直近 8 ターン (= 4 往復) に圧縮。 ObjectStore 肥大と prompt 長を抑える。
var tail = if (sizeOf(all) > 8) (all[-8 to -1]) else all
---
write(tail, "application/json") as String
